@layer components;
.accordion {
@apply relative;
}
.accordion-item {
@apply relative;
}
.accordion-header {
@apply py-2 px-4 cursor-pointer;
}
.accordion-description {
@apply hidden;
}
.accordion-close {
@apply absolute right-0 top-0 cursor-pointer;
}
