html: <div class="accordion" id="accordion">
<details class="accordion-item" id="accordion-1">
<summary class="accordion-header" onclick="toggleAccordion(this)"><span class="font-bold">Accordion 1</span></summary>
<p class="accordion-description">This is a sample accordion.</p>
<button class="accordion-close" onclick="toggleAccordion(this)" id="close-1">Close</button>
</details>
<details class="accordion-item" id="accordion-2">
<summary class="accordion-header" onclick="toggleAccordion(this)"><span class="font-bold">Accordion 2</span></summary>
<p class="accordion-description">This is another sample accordion.</p>
<button class="accordion-close" onclick="toggleAccordion(this)" id="close-2">Close</button>
</details>
</div>
<script>
function toggleAccordion(element) {
var accordionItem = element.parentNode;
var accordionDescription = accordionItem.querySelector('.accordion-description');
var accordionClose = accordionItem.querySelector('.accordion-close');
accordionDescription.classList.toggle('hidden');
accordionClose.classList.toggle('hidden');
}
</script>
